// // This comment suggests that the counter will decrement on each clock cycle when enabled, but it actually increments.
module synchronous_counter(
    input clk,
    input enable,
    input clear,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (clear)
            count <= 0;
        else if (enable)
            count <= count + 1;
    end

endmodule
